using FluentValidation;
namespace KellyServices.PARS.Application.Features.PayrollRequests.Commands.SubmitPayrollRequest
{ public class SubmitPayrollRequestCommandValidator : AbstractValidator<SubmitPayrollRequestCommand> { public SubmitPayrollRequestCommandValidator() { RuleFor(item => item.FirstName).NotEmpty().MaximumLength(100); RuleFor(item => item.LastName).NotEmpty().MaximumLength(100); RuleFor(item => item.Email).NotEmpty().EmailAddress().MaximumLength(320); RuleFor(item => item.FromDate).LessThanOrEqualTo(item => item.ToDate); RuleFor(item => item).Must(item => !string.IsNullOrWhiteSpace(item.KellyId) || !string.IsNullOrWhiteSpace(item.TaxIdLastFour)).WithMessage("KellyId or TaxIdLastFour is required."); RuleFor(item => item.TaxIdLastFour).Matches("^[0-9]{4}$").When(item => !string.IsNullOrWhiteSpace(item.TaxIdLastFour)); } } }
